module sr_latch (input SRLatch_S, input R, output reg Q, output reg Qn);  
    always @(SRLatch_S or R) begin  
        if (SRLatch_S && R) begin  
            Q <= 1'bx;  // Undefined state  
            Qn <= 1'bx; // Undefined state  
        end  
        else if (SRLatch_S) begin  
            Q <= 1'b1;  
            Qn <= 1'b0;  
        end  
        else if (R) begin  
            Q <= 1'b0;  
            Qn <= 1'b1;  
        end  
    end  
endmodule
